module top_module(
    input [3:0] in0,
    input [3:0] in1,
    input [3:0] in2,
    input [3:0] in3,
    input [1:0] sel,
    input clk, // Added clk input to resolve the error
    output reg [3:0] out
);reg [3:0] selected_input;
reg [3:0] stage2_out;

always @(*) begin // Changed to combinational logic
    case (sel)
        2'b00: selected_input = in0; // Changed <= to = for combinational logic
        2'b01: selected_input = in1;
        2'b10: selected_input = in2;
        2'b11: selected_input = in3;
        default: selected_input = 4'b0000; // Added default case for safety
    endcase
end

always @(posedge clk) begin
    stage2_out <= selected_input;
end

assign out = stage2_out;

endmodule
